('Collective Essential Heavyweight Tee', '2500', '1800', 50, 'product1.jpg', '<p>Crafted from 100% organic heavy-weight cotton for a structured, relaxed fit. Features a classic crew neckline and minimal detailing.</p>', 'Crafted from 100% organic cotton with a relaxed fit.', '<p>Organic Cotton</p>', '<p>New</p>', '<p>30 Days Return</p>', 120, 1, 1, 1),

('Raw Edge Relaxed Hoodie', '4500', '3200', 30, 'product2.jpg', '<p>A premium loopback french terry hoodie with dropped shoulders and a raw edge hem for a modern, architectural silhouette.</p>', 'Premium loopback french terry hoodie with dropped shoulders.', '<p>French Terry</p>', '<p>New</p>', '<p>30 Days Return</p>', 85, 1, 1, 1),

('Minimalist Chino Trousers', '3500', '2800', 40, 'product3.jpg', '<p>Tailored straight-leg chinos made from a breathable stretch-cotton blend. Designed for effortless styling and all-day comfort.</p>', 'Tailored straight-leg chinos made from a stretch-cotton blend.', '<p>Stretch Cotton</p>', '<p>New</p>', '<p>30 Days Return</p>', 200, 1, 1, 2),

('Classic Oxford Shirt', '3000', '2200', 60, 'product4.jpg', '<p>The foundational Oxford shirt. Features a button-down collar, pristine white finish, and perfectly balanced proportions for any occasion.</p>', 'The foundational Oxford shirt with a pristine white finish.', '<p>Oxford Cotton</p>', '<p>New</p>', '<p>30 Days Return</p>', 150, 1, 1, 1),

('Textured Knit Polo', '2800', '2100', 25, 'product5.jpg', '<p>A sophisticated take on the classic polo. Made from an ultra-soft textured knit fabric with an open collar and clean, ribbed edges.</p>', 'Ultra-soft textured knit fabric with an open collar.', '<p>Textured Knit</p>', '<p>New</p>', '<p>30 Days Return</p>', 90, 1, 1, 1),

('Premium Wool Overcoat', '12000', '9500', 15, 'product6.jpg', '<p>An investment piece. This structured overcoat is cut from a luxurious wool-cashmere blend and features sharp lapels and a hidden button placket.</p>', 'Structured overcoat cut from a luxurious wool-cashmere blend.', '<p>Wool Cashmere</p>', '<p>New</p>', '<p>30 Days Return</p>', 320, 1, 1, 3),

('Slim Fit Selvedge Denim', '5500', '4200', 45, 'product7.jpg', '<p>Woven on vintage shuttle looms, this premium raw selvedge denim will mold perfectly to your body over time. Finished with minimal hardware.</p>', 'Premium raw selvedge denim finished with minimal hardware.', '<p>Selvedge Denim</p>', '<p>New</p>', '<p>30 Days Return</p>', 210, 1, 1, 2),

('Tailored Linen Blazer', '8500', '6500', 20, 'product8.jpg', '<p>An unstructured, lightweight linen blazer perfect for smart-casual layering. Breathable and sharply tailored for a flawless drape.</p>', 'Unstructured, lightweight linen blazer perfect for layering.', '<p>Linen</p>', '<p>New</p>', '<p>30 Days Return</p>', 110, 1, 1, 3);
